INSERT INTO board (board_id, user_id, log_id, board_title, board_content, recommend_count, created_at, updated_at) VALUES
(1, 2, 1, '안양천 산책로 징검다리 쪽 가로등 나갔어요!', '초코 산책시키다가 너무 어두워서 발목 접질릴 뻔했네요 ㅠㅠ 당분간 이쪽으로 오시는 분들 폰 손전등 켜고 다니세요!', 15, '2026-03-18 21:45:00', '2026-03-18 21:45:00'),
(2, 10, 10, '저 지금 편의점 앞인데 수상한 사람이 계속 서성여요;;', '검은색 후드티 입고 담배 피우면서 지나가는 사람들 계속 쳐다보는데 너무 무서워서 못 지나가고 있어요. 혹시 지금 이 근처 지나가시는 분 있나요?', 32, '2026-03-18 23:58:00', '2026-03-18 23:58:00'),
(3, 8, 8, '범계역 2번 출구 뒷골목 CCTV 사각지대 민원 완료', '안전신문고 앱으로 방금 민원 접수했습니다. 저번에 여기서 오토바이 날치기 미수 사건도 있었다던데, 처리 결과 나오면 다시 공유할게요.', 87, '2026-03-19 09:30:00', '2026-03-19 09:30:00'),
(4, 5, 5, '지도 앱이 알려준 길로 왔는데 길이 막혀있어요', '재개발 구역인지 펜스 쳐져 있고 완전 암흑이네요... 삥 돌아서 큰길로 나가는 중인데 땀 뻘뻘 흘렸습니다. 길 안내 업데이트가 시급하네요.', 12, '2026-03-19 20:00:00', '2026-03-19 20:00:00'),
(5, 7, 7, '✅ 중앙시장 쪽에서 야간에 안전하게 넘어가는 꿀팁 코스', '시장 문 닫으면 골목 으슥해지는데, 굳이 그쪽으로 가지 마시고 우체국 끼고 도는 대로변 쪽으로 오세요. 1분 정도 더 걸리지만 방범창 밝아서 훨씬 낫습니다.', 112, '2026-03-19 21:15:00', '2026-03-19 21:15:00'),
(6, 1, 1, '평촌학원가 심야 학원차량 매연/과속 문제', '밤 10시만 되면 학원가 앞이 난장판이네요. 애들 픽업하는 차들이 과속방지턱도 그냥 넘어가고 너무 위험해 보입니다. 다들 조심하세요.', 45, '2026-03-19 22:15:00', '2026-03-19 22:15:00'),
(7, 3, 3, '명학역 육교 엘리베이터 또 고장이네요', '어르신들이나 짐 많으신 분들 참고하세요. 지금 수리 중이라는 안내문만 붙어있고 언제 고쳐질지 모르겠습니다. 밤에는 육교 위가 어두우니 횡단보도로 돌아가세요.', 28, '2026-03-20 07:45:00', '2026-03-20 07:45:00'),
(8, 9, 9, '비산동 안심귀가 서비스 이용 후기 (대만족!)', '딸아이가 늦게 귀가해서 처음으로 안심귀가 스카우트 신청해 봤는데, 정말 친절하게 집 앞까지 동행해 주셨어요. 밤길 무서우신 분들 꼭 이용해 보세요.', 156, '2026-03-20 10:20:00', '2026-03-20 10:20:00'),
(9, 4, 4, '관악산 등산로 입구 멧돼지 출몰 주의보!!', '오늘 새벽에 종합운동장 쪽 등산로 입구에서 멧돼지 가족 봤습니다 ㅠㅠ 소방서에 바로 신고했는데, 새벽 운동 가시는 분들 당분간 조심하셔야 할 것 같아요.', 210, '2026-03-20 13:05:00', '2026-03-20 13:10:00'),
(10, 6, 6, '1번 국도변 보도블럭 파손 심각한 곳 위치 공유', '전동 킥보드 타시는 분들 특히 주의하세요! 호계구사거리 쪽 인도 보도블럭이 다 깨져서 밤에 안 보이고 푹 파여있습니다. 자전거 타다가 넘어질 뻔했네요.', 54, '2026-03-20 15:30:00', '2026-03-20 15:30:00');
INSERT INTO reply (reply_id, board_id, user_id, reply_content, created_at, updated_at) VALUES
(1, 1, 6, '헉 저도 방금 뛰다가 거기서 넘어질 뻔했어요;; 구청에 신고 넣어두겠습니다!', '2026-03-18 21:50:00', '2026-03-18 21:50:00'),
(2, 1, 3, '그쪽 원래 비 오면 자주 고장 나더라고요. 조심하세요~', '2026-03-18 22:05:00', '2026-03-18 22:05:00'),
(3, 2, 9, '학생 제가 지금 딸 마중 나가는 길인데 그쪽으로 갈게요. 맘스터치 앞 맞죠? 편의점 안에 들어가 있어요.', '2026-03-19 00:02:00', '2026-03-19 00:02:00'),
(4, 2, 10, '@딸바보아빠 헉 네 맞아요 ㅠㅠ 알바생 분한테 양해 구하고 안에 들어와 있습니다. 감사합니다 ㅠㅠ', '2026-03-19 00:05:00', '2026-03-19 00:05:00'),
(5, 3, 7, '와 행동력 대박이십니다 bbb 저도 항상 거슬렸는데 추천 누르고 가요.', '2026-03-19 10:15:00', '2026-03-19 10:15:00'),
(6, 3, 1, '야근하고 그 길 지날 때마다 이어폰 빼고 걷습니다.. 빨리 CCTV 달렸으면 좋겠네요.', '2026-03-19 11:20:00', '2026-03-19 11:20:00'),
(7, 4, 3, '거기 이달 초부터 공사 들어갔어요! 지도 앱이 아직 반영을 안 했나 보네요.', '2026-03-19 20:10:00', '2026-03-19 20:10:00'),
(8, 5, 5, '오 꿀팁 감사합니다! 내일 퇴근할 때는 그쪽으로 가봐야겠네요.', '2026-03-19 21:30:00', '2026-03-19 21:30:00'),
(9, 5, 4, '저는 그 우체국 맞은편 24시 빨래방 불빛 덕분에 밤마다 안심하면서 지나갑니다 ㅋㅋ', '2026-03-19 22:45:00', '2026-03-19 22:45:00'),
(10, 2, 3, '나중에 경찰에 순찰 강화 요청도 해봐야겠네요. 무사히 귀가하셔서 다행입니다!', '2026-03-19 08:00:00', '2026-03-19 08:00:00');
INSERT INTO article (article_title, article_date, article_content, article_url, article_writer, article_pic, article_site, article_keyword, article_district, article_created_at) VALUES
('강남역 인근 묻지마 폭행 20대 남성 검거', '2026-04-01', '강남역 인근에서 행인에게 주먹을 휘두른 남성이 시민들의 신고로 현장에서 붙잡혔습니다.', 'https://news.example.com/gangnam', '홍길동', 'https://pic.example.com/gn.jpg', '노컷뉴스', '강남구 범죄', '강남구', NOW()),
('강동구 천호동 상가 밀집지역 야간 순찰 강화', '2026-04-02', '강동경찰서는 최근 천호동 일대 상가 침입 절도 예방을 위해 도보 순찰 인력을 배가했습니다.', 'https://news.example.com/gangdong', '김철수', 'https://pic.example.com/gd.jpg', '머니투데이', '강동구 범죄', '강동구', NOW()),
('강북구 수유동 빌라 유리창 파손 사건 수사', '2026-04-01', '심야 시간대 주택가 창문을 깨고 침입하려던 흔적이 발견되어 경찰이 주변 CCTV를 분석 중입니다.', 'https://news.example.com/gangbuk', '이영희', 'https://pic.example.com/gb.jpg', '노컷뉴스', '강북구 범죄', '강북구', NOW()),
('강서구 화곡동 주거지역 스토킹 의심 신고 급증', '2026-04-03', '화곡동 일대 1인 가구 밀집 지역을 중심으로 모르는 사람이 문을 두드린다는 신고가 잇따르고 있습니다.', 'https://news.example.com/gangseo', '박민지', 'https://pic.example.com/gs.jpg', '머니투데이', '강서구 범죄', '강서구', NOW()),
('관악구 신림동 산책로 "안심 가로등" 전격 설치', '2026-04-01', '관악구는 최근 발생한 강력 범죄 예방을 위해 등산로 입구와 어두운 산책로에 스마트 가로등을 배치했습니다.', 'https://news.example.com/gwanak', '최현우', 'https://pic.example.com/ga.jpg', '노컷뉴스', '관악구 범죄', '관악구', NOW()),
('광진구 건대입구역 주변 취객 대상 "아리랑치기" 주의', '2026-04-02', '심야 시간 길가에 쓰러진 취객의 소지품을 노리는 범죄가 늘고 있어 경찰이 집중 단속에 나섰습니다.', 'https://news.example.com/gwangjin', '윤아름', 'https://pic.example.com/gj.jpg', '머니투데이', '광진구 범죄', '광진구', NOW()),
